// Reject requests whose secret header does not match AUDIT_LOG_WEBHOOK_SECRET.
// Fail-open only when no secret is configured in n8n (Variables or env), so the
// workflow keeps working until you set the secret, then enforces it.
const headers = $json.headers || {};
const provided = headers['x-instawork-audit-secret'] || headers['X-Instawork-Audit-Secret'] || '';
let expected = '';
try { if (typeof $vars !== 'undefined' && $vars && $vars.AUDIT_LOG_WEBHOOK_SECRET) expected = $vars.AUDIT_LOG_WEBHOOK_SECRET; } catch (e) {}
try { if (!expected && typeof $env !== 'undefined' && $env && $env.AUDIT_LOG_WEBHOOK_SECRET) expected = $env.AUDIT_LOG_WEBHOOK_SECRET; } catch (e) {}
const authorized = !expected || provided === expected;
return [{ json: { authorized: authorized, body: $json.body } }];

// Normalize one inbound audit event into a single, consistent sheet row.
// One row per event, same 17 columns every time, so the sheet stays clean.
// PII policy: only Name + Email are stored. File references point at AWS S3.
const event = ($json.body && typeof $json.body === 'object') ? $json.body : $json;
const NL = String.fromCharCode(10);
const FRIENDLY_EVENT = { attempt: 'Document Attempt', summary: 'Submission Summary', session_start: 'Session Started', flow_complete: 'Flow Completed', app_redirect_click: 'Opened App' };
const profile = event.profile || {};
const fullName = ([profile.legalFirstName || profile.firstName, profile.legalLastName || profile.lastName].filter(Boolean).join(' ').trim()) || event.intercomName || '';
const email = profile.email || event.intercomEmail || '';
const address = profile.residentialAddress || event.residentialAddress || '';
function flagText(flags) { if (!Array.isArray(flags) || !flags.length) return ''; return flags.map(function (f) { return f && f.code ? (f.code + ': ' + (f.message || '')).trim() : String(f); }).join(' | '); }
let flow = '', attemptNo = '', result = '', documentInfo = '', fileName = '', awsLocation = '', awsUrl = '', immigration = '', details = '';
const kind = event.recordKind || '';
if (kind === 'attempt') { flow = event.flow || ''; attemptNo = event.attemptNumber || ''; result = event.resultStatus || ''; documentInfo = event.selectedDocumentLabel || event.selectedDocumentType || ''; fileName = event.fileName || ''; awsLocation = event.s3FileKey || ''; awsUrl = event.s3FileUrl || ''; immigration = event.immigrationStatus || ''; details = [event.userMessage, flagText(event.flags)].filter(Boolean).join(' - '); }
else if (kind === 'summary') { const id = event.identity || {}; const i9 = event.i9 || {}; result = 'ID: ' + (id.finalStatus || 'n/a') + ' | I-9: ' + (i9.finalStatus || 'n/a'); documentInfo = (i9.selectedDocuments || []).join(', '); immigration = i9.citizenshipStatus || ''; const files = [].concat(id.fileLinks || [], i9.fileLinks || []); const fb = event.feedback || {}; details = [fb.rating ? ('Rating ' + fb.rating + '/5') : '', fb.comments || '', 'ID attempts: ' + (id.attemptCount || 0) + ', I-9 attempts: ' + (i9.attemptCount || 0), files.length ? ('Files:' + NL + files.join(NL)) : ''].filter(Boolean).join(NL); }
else if (kind === 'session_start') { details = event.landingUrl ? ('Landing: ' + event.landingUrl) : ''; }
else if (kind === 'flow_complete') { result = 'complete'; details = [event.feedbackRating ? ('Rating ' + event.feedbackRating + '/5') : '', event.feedbackComments || ''].filter(Boolean).join(' - '); }
else if (kind === 'app_redirect_click') { result = event.context || ''; details = event.deepLink ? ('Deep link: ' + event.deepLink) : ''; }
const row = { 'Timestamp': event.timestamp || new Date().toISOString(), 'Event': FRIENDLY_EVENT[kind] || kind || 'Unknown', 'Session ID': event.sessionId || '', 'Name': fullName, 'Email': email, 'Flow': flow, 'Attempt #': attemptNo, 'Result': result, 'Document': documentInfo, 'File Name': fileName, 'AWS File Location': awsLocation, 'AWS File URL': awsUrl, 'Immigration Status': immigration, 'Details': details, 'Address': address, 'Intercom User ID': event.intercomUserId || '', 'Intercom Ticket ID': event.intercomConversationId || '' };
return [{ json: row }];
